10→export function FreedomWallScreen() {
11→  const {colors} = useTheme();
12→  const {session} = useAuth();
13→  const token = session?.access_token;
14→
15→  const currentWeekQuery = useQuery({
16→    queryKey: ['freedom-current-week'],
17→    queryFn: () => mobileApi.getCurrentFreedomWallWeek(token),
18→  });
19→
20→  const weeksQuery = useQuery({
21→    queryKey: ['freedom-weeks'],
22→    queryFn: () => mobileApi.getFreedomWallWeeks(8, token),
23→  });
24→
25→  const activeWeekId = currentWeekQuery.data?.data?.id;
26→
27→  const itemsQuery = useQuery({
28→    queryKey: ['freedom-items', activeWeekId],
29→    enabled: Boolean(activeWeekId),
30→    queryFn: () => mobileApi.getFreedomWallItems(activeWeekId ?? '', {limit: 200}, token),
31→  });
32→
33→  return (
34→    <Screen>
35→      <Text style={[styles.title, {color: colors.textPrimary}]}>Freedom Wall</Text>
36→      <FeatureTodoCard
37→        title="Collaborative wall route wired"
38→        description="Week selection and item APIs are mapped for native implementation. Gesture board and minimap interactions are the next delivery unit."
39→      />
40→      <View
41→        style={[
42→          styles.card,
43→          {backgroundColor: colors.bgElevated, borderColor: colors.borderLight},
44→        ]}>
45→        <Text style={[styles.cardTitle, {color: colors.textPrimary}]}>Data snapshot</Text>
46→        <Text style={[styles.cardText, {color: colors.textMuted}]}>
47→          {currentWeekQuery.isLoading
48→            ? 'Loading current week...'
49→            : `Current week id: ${activeWeekId || 'Unavailable'}`}
50→        </Text>
51→        <Text style={[styles.cardText, {color: colors.textMuted}]}>
52→          {weeksQuery.isLoading
53→            ? 'Loading week list...'
54→            : `Known weeks: ${weeksQuery.data?.data?.length ?? 0}`}
55→        </Text>
56→        <Text style={[styles.cardText, {color: colors.textMuted}]}>
57→          {itemsQuery.isLoading
58→            ? 'Loading wall items...'
59→            : `Items in current week: ${itemsQuery.data?.data?.length ?? 0}`}
60→        </Text>
61→      </View>
62→    </Screen>
63→  );
64→}
65→
66→const styles = StyleSheet.create({
67→  title: {
68→    fontSize: 24,
69→    fontWeight: '800',
70→  },
71→  card: {
72→    borderWidth: 1,
73→    borderRadius: 12,
74→    padding: 12,
75→    gap: 6,
76→  },
77→  cardTitle: {
78→    fontWeight: '700',
79→    fontSize: 15,
80→  },
81→  cardText: {
82→    fontSize: 14,
83→  },
