 57→export function HomeFeedScreen({navigation}: Props) {
 58→  const {user, session} = useAuth();
 59→  const {colors} = useTheme();
 60→  const token = session?.access_token ?? '';
 61→  const [refreshing, setRefreshing] = useState(false);
 62→  const [activeFilter, setActiveFilter] = useState('all');
 63→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 64→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 65→
 66→  const feedQuery = useInfiniteQuery({
 67→    queryKey: ['feed', user?.id],
 68→    queryFn: ({pageParam}) =>
 69→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 70→    initialPageParam: null as string | null,
 71→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 72→  });
 73→
 74→  const reactionMutation = useMutation({
 75→    mutationFn: async ({
 76→      journalId,
 77→      receiverId,
 78→      reactionType,
 79→    }: {
 80→      journalId: string;
 81→      receiverId: string;
 82→      reactionType: string;
 83→    }) => {
 84→      if (!token) throw new Error('Please log in to react.');
 85→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 86→    },
 87→    onMutate: async ({journalId, reactionType}) => {
 88→      await queryClient.cancelQueries({queryKey: ['feed']});
 89→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 90→        ['feed', user?.id],
 91→      );
 92→      if (prev) {
 93→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 94→          ['feed', user?.id],
 95→          old => {
 96→            if (!old) return old;
 97→            return {
 98→              ...old,
 99→              pages: old.pages.map(page => ({
100→                ...page,
101→                data: page.data.map(item => {
102→                  if (item.id !== journalId) return item;
103→                  const removing = item.user_reaction === reactionType;
104→                  const currentCount =
105→                    (item.reaction_count?.[0]?.count ??
106→                      item.like_count?.[0]?.count ??
107→                      item.likes_count ??
108→                      0) as number;
109→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
110→                  return {
111→                    ...item,
112→                    user_reaction: removing ? null : reactionType,
113→                    has_liked: removing ? false : true,
114→                    like_count: [{count: Math.max(0, currentCount + delta)}],
115→                  };
116→                }),
117→              })),
118→            };
119→          },
120→        );
121→      }
122→      return {prev};
123→    },
124→    onError: (_err, _vars, context) => {
125→      if (context?.prev) {
126→        queryClient.setQueryData(['feed', user?.id], context.prev);
127→      }
128→    },
129→    onSettled: () => {
130→      queryClient.invalidateQueries({queryKey: ['feed']});
131→    },
132→  });
133→
134→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
135→
136→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
137→    if (!token) return;
138→    reactionMutation.mutate({journalId, receiverId, reactionType});
139→  };
140→
141→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
142→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
143→  };
144→
145→  const handleBookmark = (journalId: string) => {
146→    bookmarkMutation.mutate(journalId);
147→  };
148→
149→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
150→    setRepostModal({journalId, title, authorName, authorAvatar});
151→  };
152→
153→  const posts = useMemo(
154→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
155→    [feedQuery.data?.pages],
156→  );
157→
158→  const onRefresh = async () => {
159→    setRefreshing(true);
160→    try {
161→      await feedQuery.refetch();
162→    } finally {
163→      setRefreshing(false);
164→    }
165→  };
166→
167→  const handleQuickAction = (key: string) => {
168→    if (key === 'canvas') {
169→      navigation.navigate('Canvas');
170→    } else if (key === 'freedom_wall') {
171→      navigation.navigate('FreedomWall');
172→    } else if (key === 'universe') {
173→      navigation.navigate('Universe');
174→    } else {
175→      setActiveFilter(key);
176→    }
177→  };
178→
179→  return (
180→    <SafeAreaView
181→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
182→      edges={['top']}>
183→      {/* Branded header */}
184→      <View
185→        style={[
186→          styles.header,
187→          {borderBottomColor: colors.borderCard},
188→        ]}>
189→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
190→          iskrib
191→        </Text>
192→      </View>
193→
194→      {/* Filter chips */}
195→      <View style={styles.chipRow}>
196→        <ScrollView
197→          horizontal
198→          showsHorizontalScrollIndicator={false}
199→          contentContainerStyle={styles.chipScroll}>
200→          {QUICK_ACTIONS.map(action => (
201→            <Chip
202→              key={action.key}
203→              label={action.label}
204→              active={activeFilter === action.key}
205→              onPress={() => handleQuickAction(action.key)}
206→            />
207→          ))}
208→        </ScrollView>
209→      </View>
210→
211→      {/* Feed */}
212→      <FlatList
213→        data={posts}
214→        onRefresh={onRefresh}
215→        refreshing={refreshing}
216→        onEndReachedThreshold={0.25}
217→        onEndReached={() => {
218→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
219→            feedQuery.fetchNextPage();
220→          }
221→        }}
222→        contentContainerStyle={styles.listContent}
223→        showsVerticalScrollIndicator={false}
224→        ListEmptyComponent={
225→          feedQuery.isLoading ? (
226→            <View style={styles.skeletonList}>
227→              <PostCardSkeleton />
228→              <PostCardSkeleton />
229→              <PostCardSkeleton />
230→            </View>
231→          ) : (
232→            <EmptyState
233→              title="No posts yet"
234→              subtitle="Pull to refresh or create your first journal post."
235→            />
236→          )
237→        }
238→        ListFooterComponent={
239→          feedQuery.isFetchingNextPage ? (
240→            <View style={styles.loadingMore}>
241→              <PostCardSkeleton />
242→            </View>
243→          ) : null
244→        }
245→        keyExtractor={item => item.id}
246→        renderItem={({item}) => {
247→          const preview = extractPlainText(item.content).slice(0, 180);
248→          const likeCount = resolveCount(
249→            item.like_count,
250→            item.likes_count,
251→          );
252→          const commentCount = resolveCount(
253→            item.comment_count,
254→            item.comments_count,
255→          );
256→          const bookmarkCount = resolveCount(item.bookmark_count);
257→          const bannerImage = extractBannerImage(
258→            item.content,
259→            (item as any).images,
260→          );
261→
262→          const receiverId = item.user_id ?? item.users?.id ?? '';
263→
264→          const handleAuthorPress = () => {
265→            const authorId = item.users?.id ?? item.user_id;
266→            if (!authorId) return;
267→            if (authorId === user?.id) {
268→              navigation.navigate('Main' as any, {screen: 'Profile'});
269→            } else {
270→              navigation.navigate('VisitProfile', {
271→                userId: authorId,
272→                username: item.users?.username ?? undefined,
273→              });
274→            }
275→          };
276→
277→          const isRepost = !!item.is_repost;
278→          const repostSource = isRepost ? item.repost_source : null;
279→          const repostSourcePreview = repostSource?.content
280→            ? extractPlainText(repostSource.content).slice(0, 180)
281→            : '';
282→
283→          return (
284→            <PostCard
285→              title={item.title || 'Untitled Post'}
286→              bodyPreview={preview || 'No preview text available.'}
287→              authorName={item.users?.name || 'Unknown author'}
288→              authorAvatar={item.users?.image_url}
289→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
290→              bannerImage={bannerImage}
291→              postType={item.post_type}
292→              likeCount={likeCount}
293→              commentCount={commentCount}
294→              bookmarkCount={bookmarkCount}
295→              userReaction={item.user_reaction}
296→              isBookmarked={!!item.has_bookmarked}
297→              onReact={type => handleReact(item.id, receiverId, type)}
298→              onComment={() => handleComment(item.id, receiverId, commentCount)}
299→              onBookmark={() => handleBookmark(item.id)}
300→              onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
301→              onPress={() =>
302→                navigation.navigate('PostDetail', {journalId: item.id})
303→              }
304→              onAuthorPress={handleAuthorPress}
305→              isRepost={isRepost}
306→              repostCaption={item.repost_caption}
307→              repostSourceTitle={repostSource?.title}
308→              repostSourcePreview={repostSourcePreview}
309→              repostSourceAuthorName={repostSource?.users?.name}
310→              repostSourceAuthorAvatar={repostSource?.users?.image_url}
311→              onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
312→            />
313→          );
314→        }}
315→        ItemSeparatorComponent={() => <View style={styles.separator} />}
316→      />
317→
318→      {commentModal && (
319→        <CommentModal
320→          visible
321→          postId={commentModal.postId}
322→          receiverId={commentModal.receiverId}
323→          commentCount={commentModal.commentCount}
324→          onClose={() => setCommentModal(null)}
325→        />
326→      )}
327→
328→      {repostModal && (
329→        <RepostModal
330→          visible
331→          sourceJournalId={repostModal.journalId}
332→          title={repostModal.title}
333→          authorName={repostModal.authorName}
334→          authorAvatar={repostModal.authorAvatar}
335→          onClose={() => setRepostModal(null)}
336→        />
337→      )}
338→
339→      {/* FAB Write Button */}
340→      <Pressable
341→        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
342→        style={({pressed}) => [
343→          styles.fab,
344→          {backgroundColor: colors.accentAmber},
345→          shadows(colors).elevated,
346→          pressed && styles.fabPressed,
347→        ]}>
348→        <PenIcon size={22} color="#1A1612" />
349→      </Pressable>
350→    </SafeAreaView>
351→  );
352→}
